async function run(input) {
  var wert = String((input && input.wert != null) ? input.wert : '').trim();
  var vonBasis = (input && input.vonBasis != null) ? Number(input.vonBasis) : 10;
  if (!wert) return { fehler: 'Kein Wert angegeben.' };
  if (!(vonBasis >= 2 && vonBasis <= 36)) return { fehler: 'vonBasis muss zwischen 2 und 36 liegen.' };
  var neg = false;
  var w = wert;
  if (w[0] === '-') { neg = true; w = w.slice(1); }
  w = w.toLowerCase();
  var digits = '0123456789abcdefghijklmnopqrstuvwxyz'.slice(0, vonBasis);
  if (w.length === 0) return { fehler: 'Ungueltiger Wert.' };
  var dezimal = 0;
  for (var i = 0; i < w.length; i++) {
    var d = digits.indexOf(w[i]);
    if (d < 0) return { fehler: 'Ziffer "' + w[i] + '" ist in Basis ' + vonBasis + ' ungueltig.' };
    dezimal = dezimal * vonBasis + d;
  }
  if (neg) dezimal = -dezimal;
  var abs = Math.abs(dezimal);
  var sign = neg ? '-' : '';
  return {
    binaer: sign + abs.toString(2),
    oktal: sign + abs.toString(8),
    dezimal: dezimal,
    hexadezimal: sign + abs.toString(16).toUpperCase(),
    basis32: sign + abs.toString(32).toUpperCase(),
    bitlaenge: abs.toString(2).length
  };
}
